 1	import React, { Dispatch, FC, SetStateAction, useCallback } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Radio, Split, SplitItem } from '@patternfly/react-core';
 5	
 6	import { initialSSHCredentials } from '../utils/constants';
 7	import { SecretSelectionOption, SSHSecretDetails } from '../utils/types';
 8	
 9	type SecretSelectionRadioGroupProps = {
10	  selectedOption: SecretSelectionOption;
11	  setSelectedOption: Dispatch<SetStateAction<SecretSelectionOption>>;
12	  setSSHDetails: Dispatch<SetStateAction<SSHSecretDetails>>;
13	};
14	
15	const SecretSelectionRadioGroup: FC<SecretSelectionRadioGroupProps> = ({
16	  selectedOption,
17	  setSelectedOption,
18	  setSSHDetails,
19	}) => {
20	  const { t } = useKubevirtTranslation();
21	
22	  // Inputs should not persist between changes of secretSelectionOption
23	  const onSelectSecretOption = useCallback(
24	    (secretOption: SecretSelectionOption) => {
25	      setSelectedOption((prevSecretOption) => {
26	        if (prevSecretOption !== secretOption) {
27	          setSSHDetails((prev) => ({ ...prev, secretOption, sshPubKey: '', sshSecretName: '' }));
28	        }
29	
30	        return secretOption;
31	      });
32	    },
33	    [setSelectedOption, setSSHDetails],
34	  );
35	
36	  return (
37	    <Split className="ssh-secret-section__radio-group" hasGutter>
38	      <SplitItem>
39	        <Radio
40	          onClick={() => {
41	            onSelectSecretOption(SecretSelectionOption.none);
42	            setSSHDetails(initialSSHCredentials);
43	          }}
44	          id={SecretSelectionOption.none}
45	          isChecked={selectedOption === SecretSelectionOption.none}
46	          label={t('None')}
47	          name="ssh-secret-selection"
48	        />
49	      </SplitItem>
50	      <SplitItem>
51	        <Radio
52	          id={SecretSelectionOption.useExisting}
53	          isChecked={selectedOption === SecretSelectionOption.useExisting}
54	          label={t('Use existing')}
55	          name="ssh-secret-selection"
56	          onClick={() => onSelectSecretOption(SecretSelectionOption.useExisting)}
57	        />
58	      </SplitItem>
59	      <SplitItem>
60	        <Radio
61	          id={SecretSelectionOption.addNew}
62	          isChecked={selectedOption === SecretSelectionOption.addNew}
63	          label={t('Add new')}
64	          name="ssh-secret-selection"
65	          onClick={() => onSelectSecretOption(SecretSelectionOption.addNew)}
66	        />
67	      </SplitItem>
68	    </Split>
69	  );
70	};
71	
72	export default SecretSelectionRadioGroup;

